+export function resolveGlobalInstallSpec(params: {
+  packageName: string;
+  tag: string;
+  env?: NodeJS.ProcessEnv;
+}): string {
+  const override =
+    params.env?.OPENCLAW_UPDATE_PACKAGE_SPEC?.trim() ||
+    process.env.OPENCLAW_UPDATE_PACKAGE_SPEC?.trim();
+  if (override) {
+    return override;
+  }
+  return `${params.packageName}@${params.tag}`;
+}
